14	#include <rime/ticket.h>
15	#include <utility>
16	
17	namespace rime {
18	
19	namespace dictionary {
20	
21	struct Chunk {
22	  Table* table = nullptr;
23	  Code code;
24	  const table::Entry* entries = nullptr;
25	  size_t size = 0;
26	  size_t cursor = 0;
27	  string remaining_code;  // for predictive queries
28	  size_t matching_code_size = 0;
29	  double credibility = 0.0;
30	  double quality_len = 0.0;
31	
32	  Chunk() = default;
33	  Chunk(Table* t,
34	        const Code& c,
35	        const table::Entry* e,
36	        size_t m,
37	        double cr = 0.0,
38	        double q = 0.0)
39	      : table(t),
40	        code(c),
41	        entries(e),
42	        size(1),
43	        cursor(0),
44	        matching_code_size(m),
45	        credibility(cr),
46	        quality_len(q) {}
47	  Chunk(Table* t, const TableAccessor& a, double cr = 0.0, double q = 0.0)
48	      : Chunk(t, a, string(), cr, q) {}
49	  Chunk(Table* t,
50	        const TableAccessor& a,
51	        const string& r,
52	        double cr = 0.0,
53	        double q = 0.0)
54	      : table(t),
55	        code(a.index_code()),
56	        entries(a.entry()),
57	        size(a.remaining()),
58	        cursor(0),
59	        remaining_code(r),
60	        matching_code_size(a.index_code().size()),
61	        credibility(cr),
62	        quality_len(q) {}
63	
64	  bool is_exact_match() const { return matching_code_size == code.size(); }
65	
66	  bool is_predictive_match() const { return matching_code_size < code.size(); }
67	};
68	
69	struct QueryResult {
70	  vector<Chunk> chunks;
71	};
72	
73	bool compare_chunk_by_head_element(const Chunk& a, const Chunk& b) {
74	  if (!a.entries || a.cursor >= a.size)
75	    return false;
76	  if (!b.entries || b.cursor >= b.size)
77	    return true;
78	  if (a.is_exact_match() != b.is_exact_match())
79	    return a.is_exact_match() > b.is_exact_match();
80	  if (a.remaining_code.length() != b.remaining_code.length())
81	    return a.remaining_code.length() < b.remaining_code.length();
82	  return a.credibility + a.entries[a.cursor].weight >
83	         b.credibility + b.entries[b.cursor].weight;  // by weight desc
84	}
85	
86	struct CodeMatch {
87	  bool success;
88	  size_t depth;
89	  size_t end_pos;
90	};
91	
92	CodeMatch match_extra_code(const table::Code* extra_code,
93	                           size_t depth,
94	                           const SyllableGraph& syll_graph,
95	                           size_t current_pos,
96	                           bool predict_word) {
97	  const CodeMatch kFailed{false, 0, 0};
98	  if (!extra_code || depth >= extra_code->size)
99	    return {true, depth, current_pos};
100	  if (current_pos >= syll_graph.interpreted_length) {
101	    if (predict_word)
102	      return {true, depth, syll_graph.interpreted_length};
103	    else
104	      return kFailed;
105	  }
106	  auto index = syll_graph.indices.find(current_pos);
107	  if (index == syll_graph.indices.end())
108	    return kFailed;
109	  SyllableId current_syll_id = extra_code->at[depth];
110	  auto spellings = index->second.find(current_syll_id);
111	  if (spellings == index->second.end())
112	    return kFailed;
113	  CodeMatch best_match = kFailed;
114	  for (const SpellingProperties* props : spellings->second) {
115	    CodeMatch match = match_extra_code(extra_code, depth + 1, syll_graph,
116	                                       props->end_pos, predict_word);
117	    if (!match.success)
118	      continue;
119	    if (match.end_pos > best_match.end_pos)
120	      best_match = match;
121	  }
122	  return best_match;
123	}
124	
125	}  // namespace dictionary
126	
127	DictEntryIterator::DictEntryIterator()
128	    : query_result_(New<dictionary::QueryResult>()) {}
129	
130	void DictEntryIterator::AddChunk(dictionary::Chunk&& chunk) {
131	  query_result_->chunks.push_back(std::move(chunk));
132	  entry_count_ += chunk.size;
133	}
134	
135	void DictEntryIterator::Sort() {
136	  auto& chunks = query_result_->chunks;
137	  // partial-sort remaining chunks, move best match to chunk_index_
138	  std::partial_sort(chunks.begin() + chunk_index_,
139	                    chunks.begin() + chunk_index_ + 1, chunks.end(),
140	                    dictionary::compare_chunk_by_head_element);
141	}
142	
143	void DictEntryIterator::AddFilter(DictEntryFilter filter) {
144	  DictEntryFilterBinder::AddFilter(filter);
145	  // the introduced filter could invalidate the current or even all the
146	  // remaining entries
147	  while (!exhausted() && !filter_(Peek())) {
148	    entry_.reset();
149	    FindNextEntry();
150	  }
151	}
152	
153	an<DictEntry> DictEntryIterator::Peek() {
154	  if (!entry_ && !exhausted()) {
155	    // get next entry from current chunk
156	    const auto& chunk = query_result_->chunks[chunk_index_];
157	    const auto& e = chunk.entries[chunk.cursor];
158	    DLOG(INFO) << "creating temporary dict entry '"
159	               << chunk.table->GetEntryText(e) << "'.";
160	    entry_ = New<DictEntry>();
161	    entry_->code = chunk.code;
162	    entry_->text = chunk.table->GetEntryText(e);
163	    const double kS = 18.420680743952367;  // log(1e8)
164	    entry_->weight = e.weight - kS + chunk.credibility;
165	    entry_->quality_len = chunk.quality_len;
166	    if (!chunk.remaining_code.empty()) {
167	      entry_->comment = "~" + chunk.remaining_code;
168	      entry_->remaining_code_length = chunk.remaining_code.length();
169	    }
170	    if (chunk.is_predictive_match()) {
171	      entry_->matching_code_size = chunk.matching_code_size;
172	    }
173	  }
174	  return entry_;
175	}
176	
177	bool DictEntryIterator::FindNextEntry() {
178	  if (exhausted()) {
179	    return false;
180	  }
181	  auto& chunk = query_result_->chunks[chunk_index_];
182	  if (++chunk.cursor >= chunk.size) {
183	    ++chunk_index_;
184	  }
185	  if (exhausted()) {
186	    return false;
187	  }
188	  // reorder chunks to move the one with the best entry to head
189	  Sort();
190	  return true;
191	}
192	
193	bool DictEntryIterator::Next() {
194	  do {
195	    entry_.reset();
196	    if (!FindNextEntry()) {
197	      return false;
198	    }
199	  } while (filter_ && !filter_(Peek()));
200	  return true;
201	}
202	
203	// Note: does not apply filters
204	bool DictEntryIterator::Skip(size_t num_entries) {
205	  while (num_entries > 0) {
206	    if (exhausted())
207	      return false;
208	    auto& chunk = query_result_->chunks[chunk_index_];
209	    if (chunk.cursor + num_entries < chunk.size) {
210	      chunk.cursor += num_entries;
211	      return true;
212	    }
213	    num_entries -= (chunk.size - chunk.cursor);
214	    ++chunk_index_;
215	  }
216	  return true;
217	}
218	
219	bool DictEntryIterator::exhausted() const {
220	  return chunk_index_ >= query_result_->chunks.size();
221	}
222	
223	// Dictionary members
224	
225	Dictionary::Dictionary(string name,
226	                       vector<string> packs,
227	                       vector<of<Table>> tables,
228	                       an<Prism> prism)
229	    : name_(name),
230	      packs_(std::move(packs)),
231	      tables_(std::move(tables)),
232	      prism_(std::move(prism)) {}
233	
234	Dictionary::~Dictionary() {
235	  // should not close shared table and prism objects
236	}
237	
238	static void lookup_table(Table* table,
239	                         DictEntryCollector* collector,
240	                         const SyllableGraph& syllable_graph,
241	                         size_t start_pos,
242	                         bool predict_word,
243	                         double initial_credibility) {
244	  TableQueryResult result;
245	  if (!table->Query(syllable_graph, start_pos, &result)) {
246	    return;
247	  }
248	  // copy result
249	  for (auto& v : result) {
250	    size_t end_pos = v.first;
251	    for (TableAccessor& a : v.second) {
252	      double cr = initial_credibility + a.credibility();
253	      double q = a.quality_len();
254	      if (a.extra_code()) {
255	        do {
256	          dictionary::CodeMatch match = dictionary::match_extra_code(
257	              a.extra_code(), 0, syllable_graph, end_pos, predict_word);
258	          if (!match.success)
259	            continue;
260	          size_t matching_code_size = a.index_code().size() + match.depth;
261	          (*collector)[match.end_pos].AddChunk(
262	              {table, a.code(), a.entry(), matching_code_size, cr, q});
263	        } while (a.Next());
264	      } else {
265	        (*collector)[end_pos].AddChunk({table, a, cr, q});
266	      }
267	    }
268	  }
269	}
270	
271	an<DictEntryCollector> Dictionary::Lookup(const SyllableGraph& syllable_graph,
272	                                          size_t start_pos,
273	                                          const hash_set<string>* blacklist,
274	                                          bool predict_word,
275	                                          double initial_credibility) {
276	  if (!loaded())
277	    return nullptr;
278	  auto collector = New<DictEntryCollector>();
279	  for (const auto& table : tables_) {
280	    if (!table->IsOpen())
281	      continue;
282	    lookup_table(table.get(), collector.get(), syllable_graph, start_pos,
283	                 predict_word, initial_credibility);
284	  }
285	  if (collector->empty())
286	    return nullptr;
287	  // for each group of equal code length, sort it and filter words
288	  for (auto& v : *collector) {
289	    v.second.Sort();
290	    if (blacklist && !blacklist->empty()) {
291	      v.second.AddFilter([blacklist](an<DictEntry> entry) {
292	        return entry && !blacklist->count(entry->text);
293	      });
294	    }
295	  }
296	  return collector;
297	}
298	
299	size_t Dictionary::LookupWords(DictEntryIterator* result,
300	                               const string& str_code,
301	                               bool predictive,
302	                               size_t expand_search_limit,
303	                               const hash_set<string>* blacklist) {
304	  DLOG(INFO) << "lookup: " << str_code;
305	  if (!loaded())
306	    return 0;
307	  vector<Prism::Match> keys;
308	  if (predictive) {
309	    prism_->ExpandSearch(str_code, &keys, expand_search_limit);
310	  } else {
311	    Prism::Match match{0, 0};
312	    if (prism_->GetValue(str_code, &match.value)) {
313	      keys.push_back(match);
314	    }
315	  }
316	  DLOG(INFO) << "found " << keys.size() << " matching keys thru the prism.";
317	  size_t code_length(str_code.length());
318	  for (auto& match : keys) {
319	    SpellingAccessor accessor(prism_->QuerySpelling(match.value));
320	    while (!accessor.exhausted()) {
321	      SyllableId syllable_id = accessor.syllable_id();
322	      SpellingType type = accessor.properties().type;
323	      accessor.Next();
324	      if (type > kNormalSpelling)
325	        continue;
326	      string remaining_code;
327	      if (match.length > code_length) {
328	        string syllable = primary_table()->GetSyllableById(syllable_id);
329	        if (syllable.length() > code_length)
330	          remaining_code = syllable.substr(code_length);
331	      }
332	      for (const auto& table : tables_) {
333	        if (!table->IsOpen())
334	          continue;
335	        TableAccessor a = table->QueryWords(syllable_id);
336	        if (!a.exhausted()) {
337	          DLOG(INFO) << "remaining code: " << remaining_code;
338	          result->AddChunk({table.get(), a, remaining_code});
339	        }
340	      }
341	    }
342	  }
343	  if (blacklist && !blacklist->empty()) {
344	    result->AddFilter([blacklist](an<DictEntry> entry) {
345	      return entry && !blacklist->count(entry->text);
346	    });
347	  }
348	  return keys.size();
349	}
350	
351	bool Dictionary::Decode(const Code& code, vector<string>* result) {
352	  if (!result || tables_.empty())
353	    return false;
354	  result->clear();
355	  for (SyllableId c : code) {
356	    string s = primary_table()->GetSyllableById(c);
357	    if (s.empty())
358	      return false;
359	    result->push_back(s);
360	  }
361	  return true;
362	}
363	
364	bool Dictionary::Exists() const {
365	  return std::filesystem::exists(prism_->file_path()) && !tables_.empty() &&
366	         std::filesystem::exists(tables_[0]->file_path());
367	}
368	
369	bool Dictionary::Remove() {
370	  if (loaded())
371	    return false;
372	  prism_->Remove();
373	  for (const auto& table : tables_) {
374	    table->Remove();
375	  }
376	  return true;
377	}
378	
379	bool Dictionary::Load() {
380	  LOG(INFO) << "loading dictionary '" << name_ << "'.";
381	  if (tables_.empty()) {
382	    LOG(ERROR) << "Cannot load dictionary '" << name_
383	               << "'; it contains no tables.";
384	    return false;
385	  }
386	  auto& primary_table = tables_[0];
387	  if (!primary_table || (!primary_table->IsOpen() && !primary_table->Load())) {
388	    LOG(ERROR) << "Error loading table for dictionary '" << name_ << "'.";
389	    return false;
390	  }
391	  if (!prism_ || (!prism_->IsOpen() && !prism_->Load())) {
392	    LOG(ERROR) << "Error loading prism for dictionary '" << name_ << "'.";
393	    return false;
394	  }
395	  // packs are optional
396	  for (int i = 1; i < tables_.size(); ++i) {
397	    const auto& table = tables_[i];
398	    if (!table->IsOpen() && table->Exists() && table->Load()) {
399	      LOG(INFO) << "loaded pack: " << packs_[i - 1];
400	    }
401	  }
402	  return true;
403	}
404	
405	bool Dictionary::loaded() const {
406	  return !tables_.empty() && tables_[0]->IsOpen() && prism_ && prism_->IsOpen();
407	}
408	
409	// DictionaryComponent members
410	
411	static const ResourceType kPrismResourceType = {"prism", "", ".prism.bin"};
412	
413	static const ResourceType kTableResourceType = {"table", "", ".table.bin"};
414	
415	DictionaryComponent::DictionaryComponent()
416	    : prism_resource_resolver_(
417	          Service::instance().CreateDeployedResourceResolver(
418	              kPrismResourceType)),
419	      table_resource_resolver_(
420	          Service::instance().CreateDeployedResourceResolver(
421	              kTableResourceType)) {}
422	
423	DictionaryComponent::~DictionaryComponent() {}
424	
425	Dictionary* DictionaryComponent::Create(const Ticket& ticket) {
426	  if (!ticket.schema)
427	    return nullptr;
428	  Config* config = ticket.schema->config();
429	  string dict_name;
430	  if (!config->GetString(ticket.name_space + "/dictionary", &dict_name)) {
431	    LOG(ERROR) << ticket.name_space << "/dictionary not specified in schema '"
432	               << ticket.schema->schema_id() << "'.";
433	    return nullptr;
434	  }
435	  if (dict_name.empty()) {
436	    return nullptr;  // not requiring static dictionary
437	  }
438	  string prism_name;
439	  if (!config->GetString(ticket.name_space + "/prism", &prism_name)) {
440	    prism_name = dict_name;
441	  }
442	  vector<string> packs;
443	  if (auto pack_list = config->GetList(ticket.name_space + "/packs")) {
444	    for (const auto& item : *pack_list) {
445	      if (auto value = As<ConfigValue>(item)) {
446	        packs.push_back(value->str());
447	      }
448	    }
449	  }
